    {
      "title": "Right-Sizing Recommendations",
      "type": "row",
      "gridPos": { "h": 1, "w": 24, "x": 0, "y": 45 },
      "collapsed": false
    },
    {
      "title": "Right-Sizing Recommendations",
      "description": "CronJobs with CPU or memory efficiency ratio <0.3 (over-provisioned, wasting resources) or >0.9 (under-provisioned, risk of throttle/OOM). Efficiency = actual usage / requested.",
      "type": "table",
      "datasource": { "type": "prometheus", "uid": "${datasource}" },
      "gridPos": { "h": 10, "w": 24, "x": 0, "y": 46 },
      "fieldConfig": {
        "defaults": {},
        "overrides": [
          {
            "matcher": { "id": "byName", "options": "owner_name" },
            "properties": [
              { "id": "displayName", "value": "CronJob Name" }
            ]
          },
          {
            "matcher": { "id": "byName", "options": "namespace" },
            "properties": [
              { "id": "displayName", "value": "Namespace" }
            ]
          },
          {
            "matcher": { "id": "byName", "options": "Value #cpu_ratio" },
            "properties": [
              { "id": "displayName", "value": "CPU Efficiency" },
              { "id": "unit", "value": "percentunit" },
              {
                "id": "thresholds",
                "value": {
                  "mode": "absolute",
                  "steps": [
                    { "color": "orange", "value": null },
                    { "color": "green", "value": 0.3 },
                    { "color": "orange", "value": 0.9 },
                    { "color": "red", "value": 1.2 }
                  ]
                }
              },
              { "id": "custom.cellOptions", "value": { "type": "color-background", "mode": "basic" } }
            ]
          },
          {
            "matcher": { "id": "byName", "options": "Value #mem_ratio" },
            "properties": [
              { "id": "displayName", "value": "Memory Efficiency" },
              { "id": "unit", "value": "percentunit" },
              {
                "id": "thresholds",
                "value": {
                  "mode": "absolute",
                  "steps": [
                    { "color": "orange", "value": null },
                    { "color": "green", "value": 0.3 },
                    { "color": "orange", "value": 0.9 },
                    { "color": "red", "value": 1.2 }
                  ]
                }
              },
              { "id": "custom.cellOptions", "value": { "type": "color-background", "mode": "basic" } }
            ]
          },
          {
            "matcher": { "id": "byName", "options": "Value #cpu_req" },
            "properties": [
              { "id": "displayName", "value": "CPU Request (cores)" },
              { "id": "unit", "value": "short" }
            ]
          },
          {
            "matcher": { "id": "byName", "options": "Value #mem_req" },
            "properties": [
              { "id": "displayName", "value": "Memory Request" },
              { "id": "unit", "value": "bytes" }
            ]
          }
        ]
      },
      "options": {
        "showHeader": true,
        "sortBy": [
          { "displayName": "CPU Efficiency", "desc": false }
        ],
        "footer": {
          "show": false
        }
      },
      "transformations": [
        {
          "id": "merge",
          "options": {}
        },
        {
          "id": "organize",
          "options": {
            "excludeByName": { "Time": true },
            "renameByName": {}
          }
        },
        {
          "id": "filterByValue",
          "options": {
            "type": "or",
            "filters": [
              {
                "fieldName": "Value #cpu_ratio",
                "config": {
                  "id": "lower",
                  "options": { "value": 0.3 }
                }
              },
              {
                "fieldName": "Value #cpu_ratio",
                "config": {
                  "id": "greater",
                  "options": { "value": 0.9 }
                }
              },
              {
                "fieldName": "Value #mem_ratio",
                "config": {
                  "id": "lower",
                  "options": { "value": 0.3 }
                }
              },
              {
                "fieldName": "Value #mem_ratio",
                "config": {
                  "id": "greater",
                  "options": { "value": 0.9 }
                }
              }
            ]
          }
        }
      ],
      "targets": [
        {
          "expr": "cronjob:cpu_cost_ratio{namespace=~\"$namespace\"}",
          "format": "table",
          "instant": true,
          "legendFormat": "",
          "refId": "cpu_ratio"
        },
        {
          "expr": "cronjob:memory_cost_ratio{namespace=~\"$namespace\"}",
          "format": "table",
          "instant": true,
          "legendFormat": "",
          "refId": "mem_ratio"
        },
        {
          "expr": "cronjob:cpu_request_cores:avg{namespace=~\"$namespace\"}",
          "format": "table",
          "instant": true,
          "legendFormat": "",
          "refId": "cpu_req"
        },
        {
          "expr": "cronjob:memory_request_bytes:avg{namespace=~\"$namespace\"}",
          "format": "table",
          "instant": true,
          "legendFormat": "",
          "refId": "mem_req"
        }
      ]
    }
