apiVersion: v1
kind: ConfigMap
metadata:
  name: grafana-dashboard-chargeback-report
  namespace: monitoring
  labels:
    grafana_dashboard: "1"
    app.kubernetes.io/part-of: kube-prometheus-stack
  annotations:
    grafana_folder: "Cost Tracking"
    description: "Monthly chargeback report dashboard - per-CronJob CSV export for finance"
data:
  # Dashboard JSON provisioned via Grafana sidecar (watches for ConfigMaps with label grafana_dashboard: "1").
  # DATA SOURCE: Dashboard uses ${datasource} template variable - point to Mimir for long-term queries
  # (365-day retention, Azure Blob: mimir-blocks).
  #
  # USAGE: Ana selects namespace + month time range, then exports via Inspect > Data > Download CSV.
  # Cost rates are configurable via template variables ($cpu_cost_per_core_hour, $memory_cost_per_gib_hour).
  #
  # DEPENDENCIES:
  #   - Story 6.1: Per-CronJob recording rules (Tier 1)
  #   - Story 6.2: Hourly aggregation rules (Tier 2) - cronjob:*:sum_1h metrics
  #
  # Provisioning methods:
  #   kubectl: kubectl apply -f chargeback-report-configmap.yaml -n monitoring
  #   Terraform (monitoring module exists):
  #     resource "kubernetes_config_map" "grafana_dashboard_chargeback_report" {
  #       metadata {
  #         name      = "grafana-dashboard-chargeback-report"
  #         namespace = var.monitoring_namespace
  #         labels = { grafana_dashboard = "1" }
  #       }
  #       data = {
  #         "chargeback-report.json" = file("${path.module}/../../k8s/platform/monitoring/dashboards/chargeback-report.json")
  #       }
  #     }
  chargeback-report.json: |
    {
      "annotations": {
        "list": [
          {
            "builtIn": 1,
            "datasource": { "type": "grafana", "uid": "-- Grafana --" },
            "enable": true,
            "hide": true,
            "iconColor": "rgba(0, 211, 255, 1)",
            "name": "Annotations & Alerts",
            "type": "dashboard"
          }
        ]
      },
      "description": "Monthly chargeback report for CSV export. Select a namespace and set the time range to the desired month, then use Inspect > Data > Download CSV to export. Cost formula: (CPU-seconds x cpu_rate / 3600) + (memory-bytes-seconds x memory_rate / (1073741824 x 3600)). Part of Epic 6 Cost Tracking & Chargeback (Story 6.3).",
      "editable": true,
      "fiscalYearStartMonth": 0,
      "graphTooltip": 1,
      "id": null,
      "links": [
        {
          "asDropdown": false,
          "icon": "external link",
          "includeVars": true,
          "keepTime": true,
          "tags": ["cost-tracking"],
          "targetBlank": true,
          "title": "Namespace Cost Dashboard (Story 6.2)",
          "type": "dashboards"
        },
        {
          "asDropdown": false,
          "icon": "external link",
          "includeVars": true,
          "keepTime": true,
          "tags": ["cost-tracking"],
          "targetBlank": true,
          "title": "CronJob Cost Tracking (Story 6.1)",
          "type": "dashboards"
        }
      ],
      "panels": [
        {
          "title": "Export Instructions",
          "type": "text",
          "gridPos": { "h": 4, "w": 24, "x": 0, "y": 0 },
          "options": {
            "mode": "markdown",
            "content": "## Monthly Chargeback Report Export\n\n**How to export:** 1) Select the **Namespace** and adjust **Cost Rates** above. 2) Set the **time range** to the desired month (e.g. 2026-03-01 to 2026-03-31). 3) On the table below, click the panel title > **Inspect** > **Data** tab > **Download CSV**. 4) Name the file: `chargeback-{namespace}-{YYYY-MM}.csv`.\n\n**Cost formula:** `Estimated Cost = (CPU-Seconds x CPU Cost per Core-Hour / 3600) + (Memory-Bytes-Seconds x Memory Cost per GiB-Hour / (1073741824 x 3600))`"
          }
        },
        {
          "title": "Monthly Chargeback Table",
          "description": "Per-CronJob cost breakdown for the selected namespace and time range. Use Inspect > Data > Download CSV to export this table. The TOTAL row is included via table footer.",
          "type": "table",
          "datasource": { "type": "prometheus", "uid": "${datasource}" },
          "gridPos": { "h": 16, "w": 24, "x": 0, "y": 4 },
          "fieldConfig": {
            "defaults": {},
            "overrides": [
              {
                "matcher": { "id": "byName", "options": "owner_name" },
                "properties": [
                  { "id": "displayName", "value": "CronJob Name" },
                  { "id": "custom.width", "value": 280 }
                ]
              },
              {
                "matcher": { "id": "byName", "options": "Value #executions" },
                "properties": [
                  { "id": "displayName", "value": "Execution Count" },
                  { "id": "unit", "value": "short" },
                  { "id": "decimals", "value": 0 }
                ]
              },
              {
                "matcher": { "id": "byName", "options": "Value #cpu" },
                "properties": [
                  { "id": "displayName", "value": "CPU-Seconds" },
                  { "id": "unit", "value": "short" },
                  { "id": "decimals", "value": 2 }
                ]
              },
              {
                "matcher": { "id": "byName", "options": "Value #memory" },
                "properties": [
                  { "id": "displayName", "value": "Memory-Bytes-Seconds" },
                  { "id": "unit", "value": "short" },
                  { "id": "decimals", "value": 0 }
                ]
              },
              {
                "matcher": { "id": "byName", "options": "Value #duration" },
                "properties": [
                  { "id": "displayName", "value": "Duration-Seconds" },
                  { "id": "unit", "value": "short" },
                  { "id": "decimals", "value": 2 }
                ]
              },
              {
                "matcher": { "id": "byName", "options": "Value #cost" },
                "properties": [
                  { "id": "displayName", "value": "Estimated Cost" },
                  { "id": "unit", "value": "currencyUSD" },
                  { "id": "decimals", "value": 4 }
                ]
              }
            ]
          },
          "options": {
            "showHeader": true,
            "sortBy": [{ "displayName": "Estimated Cost", "desc": true }],
            "footer": {
              "show": true,
              "reducer": ["sum"],
              "countRows": false,
              "fields": [
                "Value #executions",
                "Value #cpu",
                "Value #memory",
                "Value #duration",
                "Value #cost"
              ]
            }
          },
          "transformations": [
            { "id": "merge", "options": {} },
            {
              "id": "organize",
              "options": {
                "excludeByName": { "Time": true, "namespace": true },
                "indexByName": {
                  "owner_name": 0,
                  "Value #executions": 1,
                  "Value #cpu": 2,
                  "Value #memory": 3,
                  "Value #duration": 4,
                  "Value #cost": 5
                },
                "renameByName": {}
              }
            }
          ],
          "targets": [
            {
              "expr": "sum by (owner_name) (\n  sum_over_time(cronjob:execution_count:sum_1h{namespace=\"$namespace\"}[$__range])\n)",
              "format": "table",
              "instant": true,
              "legendFormat": "",
              "refId": "executions"
            },
            {
              "expr": "sum by (owner_name) (\n  sum_over_time(cronjob:cpu_cost_seconds:sum_1h{namespace=\"$namespace\"}[$__range])\n)",
              "format": "table",
              "instant": true,
              "legendFormat": "",
              "refId": "cpu"
            },
            {
              "expr": "sum by (owner_name) (\n  sum_over_time(cronjob:memory_cost_bytes:sum_1h{namespace=\"$namespace\"}[$__range])\n)",
              "format": "table",
              "instant": true,
              "legendFormat": "",
              "refId": "memory"
            },
            {
              "expr": "sum by (owner_name) (\n  sum_over_time(cronjob:execution_count:sum_1h{namespace=\"$namespace\"}[$__range])\n)\n* on (owner_name)\navg by (owner_name) (\n  avg_over_time(cronjob:execution_duration_seconds:avg_1h{namespace=\"$namespace\"}[$__range])\n)",
              "format": "table",
              "instant": true,
              "legendFormat": "",
              "refId": "duration"
            },
            {
              "expr": "(\n  sum by (owner_name) (\n    sum_over_time(cronjob:cpu_cost_seconds:sum_1h{namespace=\"$namespace\"}[$__range])\n  ) * $cpu_cost_per_core_hour / 3600\n)\n+\n(\n  sum by (owner_name) (\n    sum_over_time(cronjob:memory_cost_bytes:sum_1h{namespace=\"$namespace\"}[$__range])\n  ) * $memory_cost_per_gib_hour / (1073741824 * 3600)\n)",
              "format": "table",
              "instant": true,
              "legendFormat": "",
              "refId": "cost"
            }
          ]
        }
      ],
      "schemaVersion": 39,
      "tags": ["cost-tracking", "chargeback", "export", "cronjob"],
      "templating": {
        "list": [
          {
            "current": {},
            "hide": 0,
            "includeAll": false,
            "label": "Data Source",
            "multi": false,
            "name": "datasource",
            "options": [],
            "query": "prometheus",
            "refresh": 1,
            "regex": "",
            "skipUrlSync": false,
            "type": "datasource"
          },
          {
            "current": {},
            "datasource": { "type": "prometheus", "uid": "${datasource}" },
            "definition": "label_values(cronjob:cpu_cost_seconds:sum_1h, namespace)",
            "hide": 0,
            "includeAll": false,
            "label": "Namespace",
            "multi": false,
            "name": "namespace",
            "options": [],
            "query": {
              "qryType": 1,
              "query": "label_values(cronjob:cpu_cost_seconds:sum_1h, namespace)"
            },
            "refresh": 2,
            "regex": "",
            "skipUrlSync": false,
            "sort": 1,
            "type": "query"
          },
          {
            "current": { "selected": false, "text": "1.0", "value": "1.0" },
            "hide": 0,
            "label": "CPU Cost per Core-Hour ($)",
            "name": "cpu_cost_per_core_hour",
            "options": [
              { "selected": false, "text": "0.5", "value": "0.5" },
              { "selected": true, "text": "1.0", "value": "1.0" },
              { "selected": false, "text": "2.0", "value": "2.0" },
              { "selected": false, "text": "3.0", "value": "3.0" },
              { "selected": false, "text": "5.0", "value": "5.0" },
              { "selected": false, "text": "10.0", "value": "10.0" }
            ],
            "query": "0.5,1.0,2.0,3.0,5.0,10.0",
            "skipUrlSync": false,
            "type": "custom"
          },
          {
            "current": { "selected": false, "text": "1.0", "value": "1.0" },
            "hide": 0,
            "label": "Memory Cost per GiB-Hour ($)",
            "name": "memory_cost_per_gib_hour",
            "options": [
              { "selected": false, "text": "0.1", "value": "0.1" },
              { "selected": false, "text": "0.25", "value": "0.25" },
              { "selected": false, "text": "0.5", "value": "0.5" },
              { "selected": true, "text": "1.0", "value": "1.0" },
              { "selected": false, "text": "2.0", "value": "2.0" },
              { "selected": false, "text": "5.0", "value": "5.0" }
            ],
            "query": "0.1,0.25,0.5,1.0,2.0,5.0",
            "skipUrlSync": false,
            "type": "custom"
          }
        ]
      },
      "time": { "from": "now-30d", "to": "now" },
      "timepicker": {
        "hidden": false,
        "refresh_intervals": ["5s", "10s", "30s", "1m", "5m"],
        "time_options": ["5m", "15m", "1h", "6h", "12h", "24h", "2d", "7d", "30d"]
      },
      "refresh": "",
      "timezone": "browser",
      "title": "Chargeback Report",
      "uid": "chargeback-report",
      "version": 1
    }
